class UserProfile extends Equatable{final String uid,phone; final String? displayName,photoUrl,city,township; final UserRole role; final UserStatus status; final int trustScore,reviewCount; final double ratingAverage; final bool notificationEnabled,isOnline; final DateTime createdAt,updatedAt; final DateTime? lastSeen; const UserProfile({required this.uid,required this.phone,this.displayName,this.photoUrl,this.city,this.township,this.role=UserRole.user,this.status=UserStatus.active,this.trustScore=0,this.ratingAverage=0,this.reviewCount=0,this.notificationEnabled=true,this.isOnline=false,required this.createdAt,required this.updatedAt,this.lastSeen}); String get nameOrPhone=>(displayName?.trim().isNotEmpty??false)?displayName!:phone; factory UserProfile.fromMap(Map<String,dynamic> map)=>UserProfile(uid:MapUtils.stringValue(map,'uid'),phone:MapUtils.stringValue(map,'phone'),displayName:map['displayName'] as String?,photoUrl:map['photoUrl'] as String?,city:map['city'] as String?,township:map['township'] as String?,role:EnumParser.fromName(values:UserRole.values,name:map['role'] as String?,fallback:UserRole.user),status:EnumParser.fromName(values:UserStatus.values,name:map['status'] as String?,fallback:UserStatus.active),trustScore:MapUtils.intValue(map,'trustScore'),ratingAverage:MapUtils.doubleValue(map,'ratingAverage'),reviewCount:MapUtils.intValue(map,'reviewCount'),notificationEnabled:MapUtils.boolValue(map,'notificationEnabled',fallback:true),isOnline:MapUtils.boolValue(map,'isOnline'),createdAt:DateParser.fromValue(map['createdAt'])??DateTime.now(),updatedAt:DateParser.fromValue(map['updatedAt'])??DateTime.now(),lastSeen:DateParser.fromValue(map['lastSeen'])); @override List<Object?> get props=>[uid,phone,displayName,photoUrl,city,township,role,status,trustScore,ratingAverage,reviewCount,notificationEnabled,isOnline,createdAt,updatedAt,lastSeen];}
